mapper.select:
select book_content.*, book.name as bookName, chapter.name as chapterName from `book_content` left join `book` on book_content.book_id = book.id left join `chapter` on book_content.chapter_id = chapter.id
and chapter.name like concat('%', #{chapterName}, '%') and book.name like concat('%', #{bookName}, '%') and book_content.chapter_id = #{chapterId} and book_content.book_id = #{bookId}
order by book_content.id asc
